UPDATE public.questions SET
  stimulus_text = 'The scientist had discovered a new species of butterfly, but it was so small that it could only be seen with a microscope. The scientist also discovered that the butterfly was only active at night and that it had a unique, very complex mating ritual. The scientist’s findings were published in a scientific journal, and they were soon picked up by the popular press.',
